esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Query controller queueing and memory budget
| WHERE COALESCE(metrics.qc_queueing_active, qc_queueing_active) IS NOT NULL
    OR COALESCE(metrics.qc_memory_unused_bytes, qc_memory_unused_bytes) IS NOT NULL
// Get latest values per host (gauges)
| STATS max_queueing = MAX(COALESCE(metrics.qc_queueing_active, qc_queueing_active)),
    min_memory_unused = MIN(COALESCE(metrics.qc_memory_unused_bytes, qc_memory_unused_bytes))
  BY host.name
// Alert when queueing is high (>= 5) or memory budget exhausted (< 10MB)
// Adjust thresholds for your workload
| WHERE max_queueing >= 5 OR (min_memory_unused IS NOT NULL AND min_memory_unused < 10485760)
